// Parse AI response and update document record
const extractInfo = $('Extract Text from Server').first().json;
const aiResponse = $input.first().json;

let metadata = { category: 'other', description: '', fiscalPeriod: null, isTemplate: false };

try {
  let responseText = aiResponse.message?.content || aiResponse.text || '';
  const jsonMatch = responseText.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    metadata = JSON.parse(jsonMatch[0]);
  }
} catch (e) {
  metadata.description = 'Failed to parse AI response';
}

return [{
  json: {
    documentId: extractInfo.document_id,
    orgId: extractInfo.org_id || '',
    extractedText: extractInfo.extracted_text || '',
    aiCategory: metadata.category || 'other',
    description: metadata.description || '',
    fiscalPeriod: metadata.fiscalPeriod || null,
    isTemplate: metadata.isTemplate || false
  }
}];

// Match requested document types to Supabase documents
const requestBody = $('Document Retrieval Webhook (DB)').first().json.body;
const requiredDocs = requestBody.requiredDocs || [];

const response = $('Get All Documents from DB').first().json;
const allDocs = response.documents || [];

// Filter to active/completed documents
const activeDocs = allDocs.filter(d => d.extraction_status === 'completed' || d.ai_category);

const matchedDocs = {};
const missingDocs = [];

for (const docType of requiredDocs) {
  // Match by ai_category or category
  const matches = activeDocs.filter(d => 
    d.ai_category === docType || d.category === docType
  );

  if (matches.length > 0) {
    // Get the most recent one
    const latest = matches[0]; // Already sorted by created_at desc from the API
    matchedDocs[docType] = {
      found: true,
      id: latest.id,
      fileName: latest.name,
      category: latest.ai_category || latest.category,
      extractedText: latest.extracted_text || '',
      extractionStatus: latest.extraction_status,
      createdAt: latest.created_at
    };
  } else {
    missingDocs.push(docType);
    matchedDocs[docType] = {
      found: false,
      message: 'No ' + docType + ' document found in vault'
    };
  }
}

return [{
  json: {
    success: missingDocs.length === 0,
    requestedCount: requiredDocs.length,
    foundCount: requiredDocs.length - missingDocs.length,
    missingDocs: missingDocs,
    documents: matchedDocs,
    retrievedAt: new Date().toISOString()
  }
}];
